cd /tmp/sv-27036e1caa7b46c695f3e2130191a02f/moderate-msbuild-properties && dotnet package list --format json > after-cpm-packages.json 2>/dev/null && python3 -c "
import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def extract(data):
    pkgs = {}
    for proj in data['projects']:
        pname = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                pkgs[(pname, pkg['id'])] = pkg['resolvedVersion']
    return pkgs

b = extract(baseline)
a = extract(after)

changes = []
unchanged = []
for key in sorted(set(b.keys()) | set(a.keys())):
    proj, pkg = key
    bv = b.get(key)
    av = a.get(key)
    if bv == av:
        unchanged.append((proj, pkg, bv))
    else:
        changes.append((proj, pkg, bv, av))

if changes:
    print('CHANGES:')
    for c in changes: print(f'  {c}')
else:
    print('No version changes - conversion is fully version-neutral')

print(f'\nUnchanged packages: {len(unchanged)}')
for u in unchanged: print(f'  {u[0]}: {u[1]} @ {u[2]}')
"

